// Replace a cross-database join in the request path with a local projection refreshed by events.
export async function handleCustomerUpdated(event: CustomerUpdated) {
  await reportingDb.query(
    `insert into customer_projection (customer_id, tenant_id, plan, updated_at)
     values ($1, $2, $3, $4)
     on conflict (customer_id) do update set plan = excluded.plan, updated_at = excluded.updated_at`,
    [event.customerId, event.tenantId, event.plan, event.updatedAt],
  );
}

export function reportQuery(tenantId: string) {
  return reportingDb.query('select plan, count(*) from customer_projection where tenant_id = $1 group by plan', [tenantId]);
}

